def gen(rng, size):
    n = max(3, size)
    nums = []
    while len(nums) < n:
        if rng.random() < 0.3:
            a = rng.randint(1, 50)
            b = rng.randint(1, 50)
            run = [a, b]
            L = rng.randint(1, 6)
            for _ in range(L):
                nxt = run[-1] + run[-2]
                if nxt > 10**9:
                    break
                run.append(nxt)
            nums.extend(run)
        else:
            nums.append(rng.randint(1, 10**9))
    return [nums[:n]]

