class Solution:
    def longestSubarray(self, nums):
        n = len(nums)
        best = min(n, 2)
        for i in range(n):
            for j in range(i + 2, n):
                ok = True
                for t in range(i + 2, j + 1):
                    if nums[t] != nums[t-1] + nums[t-2]:
                        ok = False
                        break
                if ok:
                    best = max(best, j - i + 1)
                else:
                    break
        return best

