class Solution:
    def longestSubarray(self, nums):
        n = len(nums)
        if n < 3:
            return n
        best = 2
        cur = 2
        for i in range(2, n):
            if nums[i] == nums[i-1] + nums[i-2]:
                cur += 1
            else:
                cur = 2
            if cur > best:
                best = cur
        return best

