var longestSubarray = function(nums) {
    const n = nums.length;
    if (n < 3) return n;
    let best = 2;
    let cur = 2;
    for (let i = 2; i < n; i++) {
        if (nums[i] === nums[i-1] + nums[i-2]) cur++; else cur = 2;
        if (cur > best) best = cur;
    }
    return best;
};
